#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *A = (int*)malloc(N*sizeof(int));
        int *B = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d",&A[i]);
        for(int i=0;i<N;i++) scanf("%d",&B[i]);
        int ans=0;
        for(int bit=30;bit>=0;--bit){
            int cand = ans | (1<<bit);
            int ok=1;
            for(int i=0;i<N;i++){
                if( ((A[i]&cand)!=cand) && ((B[i]&cand)!=cand) ) { ok=0; break; }
            }
            if(ok) ans=cand;
        }
        int flips=0;
        for(int i=0;i<N;i++){
            if( (A[i]&ans)!=ans && (B[i]&ans)==ans ) flips++;
        }
        printf("%d %d\n",ans,flips);
        free(A); free(B);
    }
    return 0;
}

