import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) A[i] = fs.nextInt();
            for (int i = 0; i < N; i++) B[i] = fs.nextInt();
            int ans = 0;
            for (int bit = 30; bit >= 0; --bit) {
                int cand = ans | (1 << bit);
                boolean ok = true;
                for (int i = 0; i < N; i++) {
                    if ( (A[i] & cand) != cand && (B[i] & cand) != cand ) { ok = false; break; }
                }
                if (ok) ans = cand;
            }
            int flips = 0;
            for (int i = 0; i < N; i++) {
                if ( (A[i] & ans) != ans && (B[i] & ans) == ans ) flips++;
            }
            sb.append(ans).append(' ').append(flips).append('\n');
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is){ in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
    }
}

