import sys

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        A = [next(it) for _ in range(N)]
        B = [next(it) for _ in range(N)]
        ans = 0
        for bit in range(30, -1, -1):
            cand = ans | (1 << bit)
            ok = True
            for a, b in zip(A, B):
                if (a & cand) != cand and (b & cand) != cand:
                    ok = False
                    break
            if ok:
                ans = cand
        flips = 0
        for a, b in zip(A, B):
            if (a & ans) != ans and (b & ans) == ans:
                flips += 1
        out_lines.append(f"{ans} {flips}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

